import React, { useEffect, useState } from 'react';
import api from '../../services/api';
import Navbar from '../../components/common/Navbar';
import GlassCard from '../../components/common/GlassCard';
import { Users, Calendar, DollarSign, Activity } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

const AdminDashboard = () => {
    const [stats, setStats] = useState(null);

    useEffect(() => {
        const fetchStats = async () => {
            try {
                const { data } = await api.get('/admin/stats');
                setStats(data.data);
            } catch (err) {
                console.error("Error cargando stats", err);
            }
        };
        fetchStats();
    }, []);

    const mockData = [
        { name: 'Ene', bookings: 40 },
        { name: 'Feb', bookings: 30 },
        { name: 'Mar', bookings: 50 },
        { name: 'Abr', bookings: 80 },
        { name: 'May', bookings: 60 }
    ];

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col">
            <Navbar />
            <div className="flex flex-1 pt-16">
                {/* Sidebar (simplified) */}
                <aside className="w-64 bg-white border-r hidden md:block">
                    <div className="p-4">
                        <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-4">Menú</h3>
                        <ul className="space-y-2">
                            <li className="bg-primary/10 text-primary font-bold px-4 py-2 rounded-lg cursor-pointer">Dashboard</li>
                            <li className="hover:bg-gray-100 text-gray-700 px-4 py-2 rounded-lg cursor-pointer">Usuarios</li>
                            <li className="hover:bg-gray-100 text-gray-700 px-4 py-2 rounded-lg cursor-pointer">Cuidadores</li>
                            <li className="hover:bg-gray-100 text-gray-700 px-4 py-2 rounded-lg cursor-pointer">Pagos</li>
                        </ul>
                    </div>
                </aside>

                <main className="flex-1 p-8">
                    <h1 className="text-3xl font-bold text-dark mb-8">Panel de Administración</h1>

                    {/* Stats Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
                        <GlassCard className="flex items-center gap-4 border-l-4 border-l-primary">
                            <div className="bg-primary/10 p-4 rounded-full">
                                <Users className="text-primary" size={24}/>
                            </div>
                            <div>
                                <p className="text-gray-500 text-sm font-medium">Usuarios Totales</p>
                                <p className="text-2xl font-bold text-dark">{stats?.users?.total || 0}</p>
                            </div>
                        </GlassCard>
                        <GlassCard className="flex items-center gap-4 border-l-4 border-l-secondary">
                            <div className="bg-secondary/10 p-4 rounded-full">
                                <Calendar className="text-secondary" size={24}/>
                            </div>
                            <div>
                                <p className="text-gray-500 text-sm font-medium">Reservas Activas</p>
                                <p className="text-2xl font-bold text-dark">{stats?.bookings?.total || 0}</p>
                            </div>
                        </GlassCard>
                        <GlassCard className="flex items-center gap-4 border-l-4 border-l-green-500">
                            <div className="bg-green-100 p-4 rounded-full">
                                <DollarSign className="text-green-600" size={24}/>
                            </div>
                            <div>
                                <p className="text-gray-500 text-sm font-medium">Ingresos Totales (10%)</p>
                                <p className="text-2xl font-bold text-dark">${stats?.revenue?.total_fees?.toFixed(2) || '0.00'}</p>
                            </div>
                        </GlassCard>
                        <GlassCard className="flex items-center gap-4 border-l-4 border-l-yellow-500">
                            <div className="bg-yellow-100 p-4 rounded-full">
                                <Activity className="text-yellow-600" size={24}/>
                            </div>
                            <div>
                                <p className="text-gray-500 text-sm font-medium">Pagos Pendientes</p>
                                <p className="text-2xl font-bold text-dark">0</p>
                            </div>
                        </GlassCard>
                    </div>

                    {/* Charts & Tables */}
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                        <GlassCard className="lg:col-span-2">
                            <h3 className="text-lg font-bold mb-4">Reservas (Últimos 6 Meses)</h3>
                            <div className="h-64">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={mockData}>
                                        <XAxis dataKey="name" />
                                        <YAxis />
                                        <Tooltip />
                                        <Bar dataKey="bookings" fill="#4f46e5" radius={[4, 4, 0, 0]} />
                                    </BarChart>
                                </ResponsiveContainer>
                            </div>
                        </GlassCard>

                        <GlassCard>
                            <h3 className="text-lg font-bold mb-4">Últimos Usuarios</h3>
                            <div className="space-y-4">
                                <p className="text-gray-500 text-sm">Mostrando actividad reciente...</p>
                                {/* List items would go here */}
                            </div>
                        </GlassCard>
                    </div>
                </main>
            </div>
        </div>
    );
};

export default AdminDashboard;
